from statistics import median

def median_absolute_deviation(data):
    med = median(data)
    deviations = [abs(x - med) for x in data]
    return median(deviations)

def compute_probs(datalist: list) -> (list, list):
    """
    Computes the probabilities for fragments with at least 100 pairs supporting it and that are not more than 10 median deviations from the median.
    Handles missing values (None), negative lengths, and string-encoded numbers. Returns sorted values and handles empty or all-invalid inputs.
    """
    FILTER_MINREADS = 100
    FILTER_MEDDEV_M = 10
    # Clean data: convert strings to int, filter out None and non-positive
    cleaned = []
    for item in datalist:
        if item is None:
            continue
        if isinstance(item, str):
            try:
                item = int(item)
            except ValueError:
                continue
        if isinstance(item, (int, float)) and item > 0:
            cleaned.append(item)
    if not cleaned:
        return [], []
    med = median(cleaned)
    mad = median_absolute_deviation(cleaned)
    values = []
    probabilities = []
    for item in sorted(set(cleaned)):
        if item <= med + FILTER_MEDDEV_M * mad:
            data_count = cleaned.count(item)
            if data_count >= FILTER_MINREADS:
                values.append(item)
                probabilities.append(data_count)
    if not probabilities:
        return [], []
    count_sum = float(sum(probabilities))
    probabilities = [n / count_sum for n in probabilities]
    return values, probabilities


def main():
    # Sample list of fragment lengths observed from paired-end reads
    datalist = [8]*200 + [None]*10 + [-5]*5 + ['10']*120 + [12]*150 + [15]*90 + [20]*50
    # Compute filtered fragment lengths and their probabilities
    values, probs = compute_probs(datalist)
    print("Selected fragment lengths:", values)
    print("Their probabilities:", probs)

if __name__ == "__main__":
    main()

